typedef struct _USB_30_HUB_DESCRIPTOR {   UCHAR  bLength;
UCHAR  bDescriptorType;   UCHAR  bNumberOfPorts;
USHORT wHubCharacteristics;   UCHAR  bPowerOnToPowerGood;   UCHAR  bHubControlCurrent;
UCHAR  bHubHdrDecLat;   USHORT wHubDelay;
USHORT DeviceRemovable;
} USB_30_HUB_DESCRIPTOR, *PUSB_30_HUB_DESCRIPTOR;
成员 bLength
描述符的长度（以字节为单位）。 bDescriptorType
描述符类型。 对于 SuperSpeed 中心描述符，该值必须USB_30_HUB_DESCRIPTOR_TYPE
（0x2A）。 bNumberOfPorts
中心上的端口数。 wHubCharacteristics 中心特征。
bPowerOnToPowerGood
时间（以 2 毫秒为单位）使设备完全打开。 bHubControlCurrent
中心控制器组件的最大当前要求（以毫秒为单位）。 bHubHdrDecLat
中心数据包标头解码延迟。 wHubDelay
中心引入的平均延迟（以纳秒为单位）。 DeviceRemovable
指示是否将可移动设备附加到每个端口。
要求要求
最低支持的客户端支持的最低服务器标头

