typedef struct _USB_SUPERSPEED_ENDPOINT_COMPANION_DESCRIPTOR {   UCHAR  bLength;
UCHAR  bDescriptorType;
UCHAR  bMaxBurst;   union {
UCHAR AsUchar;     struct {
UCHAR MaxStreams : 5;       UCHAR Reserved1 : 3;
} Bulk;     struct {
UCHAR Mult : 2;
UCHAR Reserved2 : 5;
UCHAR SspCompanion : 1;
} Isochronous;   } bmAttributes;
USHORT wBytesPerInterval;
} USB_SUPERSPEED_ENDPOINT_COMPANION_DESCRIPTOR, *PUSB_SUPERSPEED_ENDPOINT_COMPANION_DESCRIPTOR;
成员 bLength
指定此描述符的长度（以字节为单位）。 bDescriptorType
指定描述符类型。 必须设置为USB_SUPERSPEED_ENDPOINT_COMPANION_DESCRIPTOR。 bMaxBurst
指定终结点作为突发的一部分可以发送或接收的最大数据包数。 bmAttributes
bmAttributes.AsUchar 指定结构的长度。 bmAttributes.Bulk
bmAttributes.Bulk.MaxStreams
指定批量终结点支持的最大流数。
bmAttributes.Bulk.Reserved1 保留。 请勿使用。
bmAttributes.Isochronous
bmAttributes.Isochronous.Mult
指定一个从零开始的数字，该数字确定可在服务间隔内发送到终结点的最大数据包数（bMaxBurst * （Mult + 1）。
bmAttributes.Isochronous.Reserved2 保留。 请勿使用。
bmAttributes.Isochronous.SspCompanion
wBytesPerInterval 每个间隔的字节数。

